// Default fallback images
const sushiRamenHero = "/images/sushi-ramen-hero.jpg";
const sushiRamenMobile = "/images/sushi-ramen-mobile.jpg";

// Template Preview Component
const TemplatePreview = ({ 
  template, 
  onClose 
}: { 
  template: Partial<HomepageTemplate>; 
  onClose: () => void;
}) => {
  const { i18n } = useTranslation();
  const currentLang = i18n.language?.split('-')[0] || 'zh';
  
  const getLocalizedText = (field: string) => {
    // Try exact language, then fall back to en, zh, pt
    const value = (template as any)[`${field}_${currentLang}`];
    if (value) return value;
    return (template as any)[`${field}_en`] || (template as any)[`${field}_zh`] || (template as any)[`${field}_pt`] || "";
  };

  const getDeviceType = () => {
    if (window.innerWidth < 640) return 'mobile';
    if (window.innerWidth < 1024) return 'tablet';
    return 'desktop';
  };

  const getOverlayOpacity = () => {
    const deviceType = getDeviceType();
    
    if (deviceType === 'mobile' && template.mobile_overlay_opacity !== null) {
      return template.mobile_overlay_opacity;
    }
    if (deviceType === 'tablet' && template.tablet_overlay_opacity !== null) {
      return template.tablet_overlay_opacity;
    }
    if (deviceType === 'desktop' && template.desktop_overlay_opacity !== null) {
      return template.desktop_overlay_opacity;
    }
    
    return template.overlay_opacity ?? 30;
  };

  const getOverlayStyle = () => {
    const baseOpacity = getOverlayOpacity() || 30;
    const direction = template.overlay_gradient_direction || 'to-b';
    
    const normalizeOpacity = (value: number | null | undefined, defaultValue: number) => {
      if (value === null || value === undefined) return defaultValue / 100;
      return value > 1 ? value / 100 : value;
    };
    
    const normalizedBaseOpacity = baseOpacity > 1 ? baseOpacity / 100 : baseOpacity;
    
    const fromOpacity = normalizeOpacity(template.overlay_gradient_from_opacity, 30) * normalizedBaseOpacity;
    const viaOpacity = normalizeOpacity(template.overlay_gradient_via_opacity, 25) * normalizedBaseOpacity;
    const toOpacity = normalizeOpacity(template.overlay_gradient_to_opacity, 40) * normalizedBaseOpacity;

    const directionMap: Record<string, string> = {
      'to-t': 'to top',
      'to-b': 'to bottom',
      'to-l': 'to left',
      'to-r': 'to right',
      'to-tl': 'to top left',
      'to-tr': 'to top right',
      'to-bl': 'to bottom left',
      'to-br': 'to bottom right'
    };

    const cssDirection = directionMap[direction] || 'to bottom';

    const colorMap: Record<string, string> = {
      'black': '0, 0, 0',
      'white': '255, 255, 255',
      'background': '0, 0, 0',
      'foreground': '255, 255, 255',
      'primary': '1, 100, 80',
      'secondary': '240, 240, 240'
    };

    const fromColor = colorMap[template.overlay_gradient_from || 'black'] || '0, 0, 0';
    const viaColor = colorMap[template.overlay_gradient_via || 'black'] || '0, 0, 0';
    const toColor = colorMap[template.overlay_gradient_to || 'black'] || '0, 0, 0';

    return {
      background: `linear-gradient(${cssDirection}, rgba(${fromColor}, ${fromOpacity}), rgba(${viaColor}, ${viaOpacity}), rgba(${toColor}, ${toOpacity}))`
    };
  };

  const mobileImg = template.mobile_image_url || sushiRamenMobile;
  const tabletImg = template.tablet_image_url || template.desktop_image_url || sushiRamenHero;
  const desktopImg = template.desktop_image_url || sushiRamenHero;
  const blurAmount = template.background_blur || 0;

  const desktopMediaType = (template as any).desktop_media_type || template.media_type || 'image';
  const tabletMediaType = (template as any).tablet_media_type || template.media_type || 'image';
  const mobileMediaType = (template as any).mobile_media_type || template.media_type || 'image';

  const mobileVideo = mobileMediaType === 'video' ? template.mobile_video_url : null;
  const tabletVideo = tabletMediaType === 'video' ? (template.tablet_video_url || template.desktop_video_url) : null;
  const desktopVideo = desktopMediaType === 'video' ? template.desktop_video_url : null;

  const title = getLocalizedText('title');
  const subtitle = getLocalizedText('subtitle');
  const description = getLocalizedText('description');
  const primaryButtonText = getLocalizedText('primary_button_text');
  const secondaryButtonText = getLocalizedText('secondary_button_text');

  return (
    <div className="relative w-full h-full">
      {/* Background Media */}
      <div className="absolute inset-0 w-full h-full">
        {/* Mobile */}
        <div className="absolute inset-0 w-full h-full sm:hidden">
          {mobileVideo ? (
            <video
              src={mobileVideo}
              autoPlay
              loop
              muted
              playsInline
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          ) : (
            <img 
              src={mobileImg || ''} 
              alt="Background" 
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
        
        {/* Tablet */}
        <div className="absolute inset-0 w-full h-full hidden sm:block lg:hidden">
          {tabletVideo ? (
            <video
              src={tabletVideo}
              autoPlay
              loop
              muted
              playsInline
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          ) : (
            <img 
              src={tabletImg || ''} 
              alt="Background" 
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
        
        {/* Desktop */}
        <div className="absolute inset-0 w-full h-full hidden lg:block">
          {desktopVideo ? (
            <video
              src={desktopVideo}
              autoPlay
              loop
              muted
              playsInline
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          ) : (
            <img 
              src={desktopImg || ''} 
              alt="Background" 
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
      </div>

      {/* Overlay */}
      <div className="absolute inset-0 z-10" style={getOverlayStyle()} />

      {/* Content */}
      <div className="absolute inset-0 z-20 flex flex-col items-center justify-center text-center px-4">
        {subtitle && (
          <p className="text-white/90 text-sm sm:text-base mb-2 drop-shadow-md">
            {subtitle}
          </p>
        )}
        {title && (
          <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-4 drop-shadow-lg">
            {title}
          </h1>
        )}
        {description && (
          <p className="text-white/80 text-base sm:text-lg max-w-2xl mb-8 drop-shadow-md">
            {description}
          </p>
        )}
        
        <div className="flex flex-wrap gap-4 justify-center">
          {primaryButtonText && (
            <Button 
              variant={(template.primary_button_variant as any) || "default"}
              size="lg"
              className="pointer-events-none"
            >
              {primaryButtonText}
            </Button>
          )}
          {secondaryButtonText && (
            <Button 
              variant={(template.secondary_button_variant as any) || "outline"}
              size="lg"
              className="pointer-events-none text-white border-white hover:bg-white/10"
            >
              {secondaryButtonText}
            </Button>
          )}
        </div>
      </div>

      {/* Device indicator */}
      <div className="absolute bottom-4 left-4 z-30 bg-black/50 text-white text-xs px-3 py-1 rounded-full">
        预览模式 - 点击右上角关闭
      </div>
    </div>
  );
};

const AdminHomepageTemplates = () => {
  const { t } = useTranslation();
  const { data: templates, isLoading } = useHomepageTemplates();
  const createTemplate = useCreateHomepageTemplate();
  const updateTemplate = useUpdateHomepageTemplate();
  const deleteTemplate = useDeleteHomepageTemplate();
  const uploadImage = useUploadTemplateImage();
  const uploadVideo = useUploadTemplateVideo();

  const [editingTemplate, setEditingTemplate] = useState<HomepageTemplate | null>(null);
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [formData, setFormData] = useState<Partial<HomepageTemplate>>({});
  const [activeTab, setActiveTab] = useState("images");
  const [previewTemplate, setPreviewTemplate] = useState<HomepageTemplate | Partial<HomepageTemplate> | null>(null);
  
  // Crop dialog state
  const [cropDialogOpen, setCropDialogOpen] = useState(false);
  const [cropImageSource, setCropImageSource] = useState<File | string | null>(null);
  const [cropDeviceType, setCropDeviceType] = useState<"desktop" | "tablet" | "mobile">("desktop");

  const handleCreate = () => {
    setFormData({
      sort_order: templates?.length || 0,
      is_active: true,
      media_type: 'image',
      desktop_media_type: 'image',
      tablet_media_type: 'image',
      mobile_media_type: 'image',
      duration: 5000,
      overlay_opacity: 40,
      overlay_gradient_direction: "to-b",
      overlay_gradient_from: "background",
      overlay_gradient_from_opacity: 30,
      overlay_gradient_via: "background",
      overlay_gradient_via_opacity: 25,
      overlay_gradient_to: "background",
      overlay_gradient_to_opacity: 40,
      background_blur: 0,
      title_zh: "发现您的亚洲美食之旅",
      title_en: "Discover Your Asian Food Journey",
      title_pt: "Descubra Sua Jornada Gastronômica Asiática",
      subtitle_zh: "您的美食之旅从这里开始",
      subtitle_en: "Your culinary journey starts here",
      subtitle_pt: "Sua jornada culinária começa aqui",
      description_zh: "探索里斯本地区最好的亚洲美食",
      description_en: "Explore the best Asian cuisine in the Lisbon area",
      description_pt: "Explore a melhor cozinha asiática na área de Lisboa",
      primary_button_text_zh: "探索餐厅",
      primary_button_text_en: "Explore Restaurants",
      primary_button_text_pt: "Explorar Restaurantes",
      primary_button_link: "/restaurants",
      primary_button_variant: "default",
      secondary_button_text_zh: "活动",
      secondary_button_text_en: "Activities",
      secondary_button_text_pt: "Atividades",
      secondary_button_link: "/activities",
      secondary_button_variant: "outline",
    });
    setIsCreateDialogOpen(true);
    setActiveTab("media");
  };

  const handleEdit = (template: HomepageTemplate) => {
    setFormData(template);
    setEditingTemplate(template);
    setActiveTab("media");
  };

  const handleSave = async () => {
    try {
      const saveData = { ...formData };

      // Auto-translate Chinese → EN/PT if Chinese fields exist but EN/PT are empty
      const fieldsToTranslate: { zhKey: string; enKey: string; ptKey: string }[] = [
        { zhKey: "title_zh", enKey: "title_en", ptKey: "title_pt" },
        { zhKey: "subtitle_zh", enKey: "subtitle_en", ptKey: "subtitle_pt" },
        { zhKey: "description_zh", enKey: "description_en", ptKey: "description_pt" },
        { zhKey: "primary_button_text_zh", enKey: "primary_button_text_en", ptKey: "primary_button_text_pt" },
        { zhKey: "secondary_button_text_zh", enKey: "secondary_button_text_en", ptKey: "secondary_button_text_pt" },
      ];

      const needsEnTranslation = fieldsToTranslate.some(f => saveData[f.zhKey] && !saveData[f.enKey]);
      const needsPtTranslation = fieldsToTranslate.some(f => saveData[f.zhKey] && !saveData[f.ptKey]);

      if (needsEnTranslation || needsPtTranslation) {
        const zhTexts = fieldsToTranslate.map(f => saveData[f.zhKey] || "");
        const combinedZh = zhTexts.join("\n---SECTION---\n");

        const translateToLang = async (lang: string) => {
          try {
            const { data: result } = await supabase.functions.invoke("translate-content", {
              body: { text: combinedZh, targetLang: lang },
            });
            if (result?.translatedText) {
              return result.translatedText.split(/---SECTION---/).map((p: string) => p.trim());
            }
          } catch {}
          return null;
        };

        const [enParts, ptParts] = await Promise.all([
          needsEnTranslation ? translateToLang("en") : null,
          needsPtTranslation ? translateToLang("pt") : null,
        ]);

        fieldsToTranslate.forEach((f, idx) => {
          if (enParts && !saveData[f.enKey] && enParts[idx]) saveData[f.enKey] = enParts[idx];
          if (ptParts && !saveData[f.ptKey] && ptParts[idx]) saveData[f.ptKey] = ptParts[idx];
        });
      }

      if (editingTemplate) {
        await updateTemplate.mutateAsync({ id: editingTemplate.id, ...saveData });
        setEditingTemplate(null);
      } else {
        await createTemplate.mutateAsync(saveData);
        setIsCreateDialogOpen(false);
      }
      setFormData({});
    } catch (error) {
      console.error("Save failed:", error);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await deleteTemplate.mutateAsync(id);
    } catch (error) {
      console.error("Delete failed:", error);
    }
  };

  const handleToggleActive = async (template: HomepageTemplate) => {
    try {
      await updateTemplate.mutateAsync({ id: template.id, is_active: !template.is_active });
    } catch (error) {
      console.error("Toggle failed:", error);
    }
  };

  // Direct upload without crop
  const handleImageFileChange = async (e: React.ChangeEvent<HTMLInputElement>, type: "desktop" | "tablet" | "mobile") => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      toast.error(t("admin.homepageTemplates.selectImageFile"));
      return;
    }

    try {
      const templateId = editingTemplate?.id || "new";
      const result = await uploadImage.mutateAsync({ file, type, templateId });
      setFormData((prev) => ({
        ...prev,
        [`${type}_image_url`]: result.url,
      }));
    } catch (error) {
      console.error("Upload failed:", error);
    }
  };

  // Open crop dialog for new image upload
  const handleImageCropClick = (e: React.ChangeEvent<HTMLInputElement>, type: "desktop" | "tablet" | "mobile") => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      toast.error(t("admin.homepageTemplates.selectImageFile"));
      return;
    }

    setCropImageSource(file);
    setCropDeviceType(type);
    setCropDialogOpen(true);
    
    // Reset the input so the same file can be selected again
    e.target.value = '';
  };

  // Open crop dialog for existing uploaded image
  const handleEditExistingImage = (imageUrl: string, type: "desktop" | "tablet" | "mobile") => {
    setCropImageSource(imageUrl);
    setCropDeviceType(type);
    setCropDialogOpen(true);
  };

  // Handle crop complete
  const handleCropComplete = async (croppedFile: File, deviceType: "desktop" | "tablet" | "mobile") => {
    try {
      const templateId = editingTemplate?.id || "new";
      const result = await uploadImage.mutateAsync({ file: croppedFile, type: deviceType, templateId });
      setFormData((prev) => ({
        ...prev,
        [`${deviceType}_image_url`]: result.url,
      }));
      toast.success(t("toast.imageCropSuccess"));
    } catch (error) {
      console.error("Upload failed:", error);
      toast.error(t("toast.uploadFailed"));
    }
  };

  // Extract first frame from video as image
  const extractVideoFirstFrame = (videoFile: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      
      video.preload = 'auto';
      video.muted = true;
      video.playsInline = true;
      video.crossOrigin = 'anonymous';
      
      let hasResolved = false;
      
      const captureFrame = () => {
        if (hasResolved) return;
        if (video.videoWidth === 0 || video.videoHeight === 0) return;
        
        // Set canvas size to video dimensions
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            if (blob && blob.size > 0) {
              hasResolved = true;
              video.pause();
              URL.revokeObjectURL(video.src);
              resolve(blob);
            } else {
              reject(new Error('Failed to create blob from canvas'));
            }
          }, 'image/jpeg', 0.95);
        } else {
          reject(new Error('Failed to get canvas context'));
        }
      };
      
      // Try multiple approaches to capture the first frame
      video.onloadedmetadata = () => {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        // Seek to beginning
        video.currentTime = 0.1; // Slight offset to ensure frame is rendered
      };
      
      video.onseeked = () => {
        // Wait a bit for the frame to actually render
        setTimeout(captureFrame, 100);
      };
      
      video.oncanplay = () => {
        // Fallback: try to capture when video can play
        if (!hasResolved && video.currentTime >= 0.1) {
          setTimeout(captureFrame, 100);
        }
      };
      
      video.onerror = (e) => {
        URL.revokeObjectURL(video.src);
        reject(new Error('Failed to load video: ' + (e as any)?.message || 'Unknown error'));
      };
      
      // Set timeout to prevent hanging
      setTimeout(() => {
        if (!hasResolved) {
          URL.revokeObjectURL(video.src);
          reject(new Error('Timeout while extracting video frame'));
        }
      }, 10000);
      
      video.src = URL.createObjectURL(videoFile);
      video.load();
    });
  };

  // Extract first frame from video URL (for existing videos)
  const extractFirstFrameFromUrl = (videoUrl: string): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      
      video.preload = 'auto';
      video.muted = true;
      video.playsInline = true;
      video.crossOrigin = 'anonymous';
      
      let hasResolved = false;
      
      const captureFrame = () => {
        if (hasResolved) return;
        if (video.videoWidth === 0 || video.videoHeight === 0) return;
        
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            if (blob && blob.size > 0) {
              hasResolved = true;
              video.pause();
              resolve(blob);
            } else {
              reject(new Error('Failed to create blob from canvas'));
            }
          }, 'image/jpeg', 0.95);
        } else {
          reject(new Error('Failed to get canvas context'));
        }
      };
      
      video.onloadedmetadata = () => {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        video.currentTime = 0.1;
      };
      
      video.onseeked = () => {
        setTimeout(captureFrame, 100);
      };
      
      video.oncanplay = () => {
        if (!hasResolved && video.currentTime >= 0.1) {
          setTimeout(captureFrame, 100);
        }
      };
      
      video.onerror = () => {
        reject(new Error('Failed to load video from URL'));
      };
      
      setTimeout(() => {
        if (!hasResolved) {
          reject(new Error('Timeout while extracting video frame from URL'));
        }
      }, 15000);
      
      video.src = videoUrl;
      video.load();
    });
  };

  // Regenerate poster images from existing videos
  const [isRegenerating, setIsRegenerating] = useState(false);
  
  const regeneratePosters = async (targetType?: "desktop" | "tablet" | "mobile") => {
    const videoTypes: Array<"desktop" | "tablet" | "mobile"> = targetType 
      ? [targetType] 
      : ["desktop", "tablet", "mobile"];
    const templateId = editingTemplate?.id || "new";
    
    const typeLabels = {
      desktop: t("common.desktop", "Desktop"),
      tablet: t("common.tablet", "Tablet"), 
      mobile: t("common.mobile", "Mobile")
    };
    
    setIsRegenerating(true);
    let successCount = 0;
    let failCount = 0;
    
    for (const type of videoTypes) {
      const videoUrl = formData[`${type}_video_url` as keyof typeof formData] as string | undefined;
      if (!videoUrl) continue;
      
      try {
        toast.info(t("toast.extractingDeviceFrame", { device: typeLabels[type] }));
        const firstFrameBlob = await extractFirstFrameFromUrl(videoUrl);
        const firstFrameFile = new File([firstFrameBlob], `${type}-poster-${Date.now()}.jpg`, { type: 'image/jpeg' });
        const imageResult = await uploadImage.mutateAsync({ file: firstFrameFile, type, templateId });
        
        setFormData((prev) => ({
          ...prev,
          [`${type}_image_url`]: imageResult.url,
        }));
        successCount++;
      } catch (error) {
        console.error(`Failed to regenerate ${type} poster:`, error);
        failCount++;
      }
    }
    
    setIsRegenerating(false);
    
    if (successCount > 0) {
      const message = targetType 
        ? t("toast.posterRegenerateSuccess", { device: typeLabels[targetType] })
        : t("toast.postersRegenerateSuccess", { count: successCount });
      toast.success(message);
    }
    if (failCount > 0) {
      toast.warning(t("toast.posterRegenFailed", { count: failCount }));
    }
    if (successCount === 0 && failCount === 0) {
      const message = targetType
        ? t("toast.noVideosToProcess", { device: typeLabels[targetType] })
        : t("toast.noVideosFound");
      toast.info(message);
    }
  };

  const handleVideoFileChange = async (e: React.ChangeEvent<HTMLInputElement>, type: "desktop" | "tablet" | "mobile") => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("video/")) {
      toast.error(t("toast.selectVideoFile"));
      return;
    }

    // Check file size (max 100MB)
    if (file.size > 100 * 1024 * 1024) {
      toast.error(t("toast.videoTooLarge"));
      return;
    }

    try {
      const templateId = editingTemplate?.id || "new";
      
      // Upload video
      const result = await uploadVideo.mutateAsync({ file, type, templateId });
      
      // Extract first frame and upload as fallback image
      try {
        toast.info(t("toast.extractingFrame"));
        const firstFrameBlob = await extractVideoFirstFrame(file);
        const firstFrameFile = new File([firstFrameBlob], `${type}-poster-${Date.now()}.jpg`, { type: 'image/jpeg' });
        const imageResult = await uploadImage.mutateAsync({ file: firstFrameFile, type, templateId });
        
        setFormData((prev) => ({
          ...prev,
          [`${type}_video_url`]: result.url,
          [`${type}_image_url`]: imageResult.url,
        }));
        toast.success(t("toast.videoAndPosterGenerated"));
      } catch (frameError) {
        console.error("Failed to extract first frame:", frameError);
        // Still set video URL even if frame extraction fails
        setFormData((prev) => ({
          ...prev,
          [`${type}_video_url`]: result.url,
        }));
        toast.warning(t("toast.videoUploadedNoPoster"));
      }
    } catch (error) {
      console.error("Upload failed:", error);
    }
  };

  const handleFieldChange = (field: string, value: any) => {
    setFormData((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  const closeDialog = () => {
    setEditingTemplate(null);
    setIsCreateDialogOpen(false);
    setFormData({});
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  const renderTemplateForm = () => (
    <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
      <TabsList className="grid w-full grid-cols-4">
        <TabsTrigger value="media">媒体</TabsTrigger>
        <TabsTrigger value="overlay">{t("admin.homepageTemplates.tabs.overlay")}</TabsTrigger>
        <TabsTrigger value="content">{t("admin.homepageTemplates.tabs.content")}</TabsTrigger>
        <TabsTrigger value="buttons">{t("admin.homepageTemplates.tabs.buttons")}</TabsTrigger>
      </TabsList>

      {/* Media Tab */}
      <TabsContent value="media" className="space-y-6 mt-4">
        {/* Target Country */}
        <div className="space-y-2 p-4 border rounded-lg bg-muted/30">
          <Label className="text-base font-medium">🌍 目标国家/地区</Label>
          <p className="text-xs text-muted-foreground">设置后，该模板仅在用户 IP 位于此国家时显示。留空则作为默认模板。</p>
          <Select
            value={(formData as any).target_country || "__default__"}
            onValueChange={(v) => handleFieldChange("target_country", v === "__default__" ? null : v)}
          >
            <SelectTrigger>
              <SelectValue placeholder="默认（全球通用）" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="__default__">🌐 默认（全球通用）</SelectItem>
              <SelectItem value="Portugal">🇵🇹 Portugal</SelectItem>
              <SelectItem value="China">🇨🇳 China</SelectItem>
              <SelectItem value="Japan">🇯🇵 Japan</SelectItem>
              <SelectItem value="South Korea">🇰🇷 South Korea</SelectItem>
              <SelectItem value="United States">🇺🇸 United States</SelectItem>
              <SelectItem value="United Kingdom">🇬🇧 United Kingdom</SelectItem>
              <SelectItem value="France">🇫🇷 France</SelectItem>
              <SelectItem value="Germany">🇩🇪 Germany</SelectItem>
              <SelectItem value="Spain">🇪🇸 Spain</SelectItem>
              <SelectItem value="Italy">🇮🇹 Italy</SelectItem>
              <SelectItem value="Brazil">🇧🇷 Brazil</SelectItem>
              <SelectItem value="Canada">🇨🇦 Canada</SelectItem>
              <SelectItem value="Australia">🇦🇺 Australia</SelectItem>
              <SelectItem value="Thailand">🇹🇭 Thailand</SelectItem>
              <SelectItem value="Vietnam">🇻🇳 Vietnam</SelectItem>
              <SelectItem value="Malaysia">🇲🇾 Malaysia</SelectItem>
              <SelectItem value="Singapore">🇸🇬 Singapore</SelectItem>
              <SelectItem value="Russia">🇷🇺 Russia</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <p className="text-sm text-muted-foreground">每个端可以独立选择图片或视频，支持混合配置（如：桌面端视频 + 移动端图片）</p>
        
        {/* Desktop Media */}
        <div className="space-y-3 p-4 border rounded-lg">
          <div className="flex items-center justify-between">
            <Label className="text-base font-medium">桌面端</Label>
            <div className="flex gap-2">
              <Button
                type="button"
                size="sm"
                variant={(formData.desktop_media_type || 'image') === 'image' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('desktop_media_type', 'image')}
                className="flex items-center gap-1"
              >
                <Image className="w-3 h-3" />
                图片
              </Button>
              <Button
                type="button"
                size="sm"
                variant={(formData.desktop_media_type || 'image') === 'video' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('desktop_media_type', 'video')}
                className="flex items-center gap-1"
              >
                <Video className="w-3 h-3" />
                视频
              </Button>
            </div>
          </div>
          {(formData.desktop_media_type || 'image') === 'image' ? (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.desktop_image_url && (
                  <div className="relative group">
                    <img src={formData.desktop_image_url} alt="Desktop" className="w-32 h-20 object-cover rounded border" />
                    <Button
                      type="button"
                      variant="secondary"
                      size="icon"
                      className="absolute inset-0 w-full h-full opacity-0 group-hover:opacity-100 transition-opacity bg-black/50 rounded"
                      onClick={() => handleEditExistingImage(formData.desktop_image_url!, "desktop")}
                      title="编辑裁剪"
                    >
                      <Crop className="w-5 h-5 text-white" />
                    </Button>
                  </div>
                )}
                <div className="flex-1 flex gap-2">
                  <Input type="file" accept="image/*" onChange={(e) => handleImageFileChange(e, "desktop")} className="flex-1" />
                  <div className="relative">
                    <Input 
                      type="file" 
                      accept="image/*" 
                      onChange={(e) => handleImageCropClick(e, "desktop")} 
                      className="absolute inset-0 opacity-0 cursor-pointer"
                      id="desktop-crop-input"
                    />
                    <Button type="button" variant="outline" size="icon" title="裁剪上传新图片">
                      <Crop className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.desktop_video_url && (
                  <video src={formData.desktop_video_url} className="w-32 h-20 object-cover rounded border" muted />
                )}
                <Input type="file" accept="video/mp4,video/webm" onChange={(e) => handleVideoFileChange(e, "desktop")} />
              </div>
              {formData.desktop_image_url && (
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <span>备用图片:</span>
                  <img src={formData.desktop_image_url} alt="Desktop poster" className="w-16 h-10 object-cover rounded border" />
                </div>
              )}
            </div>
          )}
        </div>
        
        {/* Tablet Media */}
        <div className="space-y-3 p-4 border rounded-lg">
          <div className="flex items-center justify-between">
            <Label className="text-base font-medium">平板端</Label>
            <div className="flex gap-2">
              <Button
                type="button"
                size="sm"
                variant={(formData.tablet_media_type || 'image') === 'image' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('tablet_media_type', 'image')}
                className="flex items-center gap-1"
              >
                <Image className="w-3 h-3" />
                图片
              </Button>
              <Button
                type="button"
                size="sm"
                variant={(formData.tablet_media_type || 'image') === 'video' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('tablet_media_type', 'video')}
                className="flex items-center gap-1"
              >
                <Video className="w-3 h-3" />
                视频
              </Button>
            </div>
          </div>
          {(formData.tablet_media_type || 'image') === 'image' ? (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.tablet_image_url && (
                  <div className="relative group">
                    <img src={formData.tablet_image_url} alt="Tablet" className="w-32 h-20 object-cover rounded border" />
                    <Button
                      type="button"
                      variant="secondary"
                      size="icon"
                      className="absolute inset-0 w-full h-full opacity-0 group-hover:opacity-100 transition-opacity bg-black/50 rounded"
                      onClick={() => handleEditExistingImage(formData.tablet_image_url!, "tablet")}
                      title="编辑裁剪"
                    >
                      <Crop className="w-5 h-5 text-white" />
                    </Button>
                  </div>
                )}
                <div className="flex-1 flex gap-2">
                  <Input type="file" accept="image/*" onChange={(e) => handleImageFileChange(e, "tablet")} className="flex-1" />
                  <div className="relative">
                    <Input 
                      type="file" 
                      accept="image/*" 
                      onChange={(e) => handleImageCropClick(e, "tablet")} 
                      className="absolute inset-0 opacity-0 cursor-pointer"
                      id="tablet-crop-input"
                    />
                    <Button type="button" variant="outline" size="icon" title="裁剪上传新图片">
                      <Crop className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.tablet_video_url && (
                  <video src={formData.tablet_video_url} className="w-32 h-20 object-cover rounded border" muted />
                )}
                <Input type="file" accept="video/mp4,video/webm" onChange={(e) => handleVideoFileChange(e, "tablet")} />
              </div>
              {formData.tablet_image_url && (
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <span>备用图片:</span>
                  <img src={formData.tablet_image_url} alt="Tablet poster" className="w-16 h-10 object-cover rounded border" />
                </div>
              )}
            </div>
          )}
        </div>
        
        {/* Mobile Media */}
        <div className="space-y-3 p-4 border rounded-lg">
          <div className="flex items-center justify-between">
            <Label className="text-base font-medium">移动端</Label>
            <div className="flex gap-2">
              <Button
                type="button"
                size="sm"
                variant={(formData.mobile_media_type || 'image') === 'image' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('mobile_media_type', 'image')}
                className="flex items-center gap-1"
              >
                <Image className="w-3 h-3" />
                图片
              </Button>
              <Button
                type="button"
                size="sm"
                variant={(formData.mobile_media_type || 'image') === 'video' ? 'default' : 'outline'}
                onClick={() => handleFieldChange('mobile_media_type', 'video')}
                className="flex items-center gap-1"
              >
                <Video className="w-3 h-3" />
                视频
              </Button>
            </div>
          </div>
          {(formData.mobile_media_type || 'image') === 'image' ? (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.mobile_image_url && (
                  <div className="relative group">
                    <img src={formData.mobile_image_url} alt="Mobile" className="w-32 h-20 object-cover rounded border" />
                    <Button
                      type="button"
                      variant="secondary"
                      size="icon"
                      className="absolute inset-0 w-full h-full opacity-0 group-hover:opacity-100 transition-opacity bg-black/50 rounded"
                      onClick={() => handleEditExistingImage(formData.mobile_image_url!, "mobile")}
                      title="编辑裁剪"
                    >
                      <Crop className="w-5 h-5 text-white" />
                    </Button>
                  </div>
                )}
                <div className="flex-1 flex gap-2">
                  <Input type="file" accept="image/*" onChange={(e) => handleImageFileChange(e, "mobile")} className="flex-1" />
                  <div className="relative">
                    <Input 
                      type="file" 
                      accept="image/*" 
                      onChange={(e) => handleImageCropClick(e, "mobile")} 
                      className="absolute inset-0 opacity-0 cursor-pointer"
                      id="mobile-crop-input"
                    />
                    <Button type="button" variant="outline" size="icon" title="裁剪上传新图片">
                      <Crop className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center gap-4">
                {formData.mobile_video_url && (
                  <video src={formData.mobile_video_url} className="w-32 h-20 object-cover rounded border" muted />
                )}
                <Input type="file" accept="video/mp4,video/webm" onChange={(e) => handleVideoFileChange(e, "mobile")} />
              </div>
              {formData.mobile_image_url && (
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <span>备用图片:</span>
                  <img src={formData.mobile_image_url} alt="Mobile poster" className="w-16 h-10 object-cover rounded border" />
                </div>
              )}
            </div>
          )}
        </div>

        {/* Regenerate posters button */}
        {(formData.desktop_video_url || formData.tablet_video_url || formData.mobile_video_url) && (
          <div className="pt-4 border-t">
            <div className="flex items-center justify-between">
              <div>
                <Label className="text-sm font-medium">备用图片管理</Label>
                <p className="text-xs text-muted-foreground">上传视频时会自动截取第一帧作为备用图片</p>
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button 
                    type="button" 
                    variant="outline" 
                    size="sm"
                    disabled={isRegenerating}
                  >
                    {isRegenerating ? (
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : (
                      <RefreshCw className="w-4 h-4 mr-2" />
                    )}
                    重新生成第一帧
                    <ChevronDown className="w-4 h-4 ml-2" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem onClick={() => regeneratePosters()}>
                    全部重新生成
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem 
                    onClick={() => regeneratePosters("desktop")}
                    disabled={!formData.desktop_video_url}
                    className={!formData.desktop_video_url ? "opacity-50 cursor-not-allowed" : ""}
                  >
                    仅桌面端
                  </DropdownMenuItem>
                  <DropdownMenuItem 
                    onClick={() => regeneratePosters("tablet")}
                    disabled={!formData.tablet_video_url}
                    className={!formData.tablet_video_url ? "opacity-50 cursor-not-allowed" : ""}
                  >
                    仅平板端
                  </DropdownMenuItem>
                  <DropdownMenuItem 
                    onClick={() => regeneratePosters("mobile")}
                    disabled={!formData.mobile_video_url}
                    className={!formData.mobile_video_url ? "opacity-50 cursor-not-allowed" : ""}
                  >
                    仅移动端
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.duration")}</Label>
            <Input
              type="number"
              value={formData.duration || 5000}
              onChange={(e) => handleFieldChange("duration", parseInt(e.target.value) || 5000)}
              min={1000}
              max={30000}
            />
            <p className="text-xs text-muted-foreground">{t("admin.homepageTemplates.durationHint")}</p>
          </div>
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.sortOrder")}</Label>
            <Input
              type="number"
              value={formData.sort_order || 0}
              onChange={(e) => handleFieldChange("sort_order", parseInt(e.target.value) || 0)}
            />
          </div>
        </div>
      </TabsContent>

      {/* Overlay Tab */}
      <TabsContent value="overlay" className="space-y-4 mt-4">
        <div className="space-y-4">
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.baseOverlayOpacity")}: {formData.overlay_opacity || 40}%</Label>
            <Slider
              value={[formData.overlay_opacity || 40]}
              onValueChange={([value]) => handleFieldChange("overlay_opacity", value)}
              max={100}
              step={1}
            />
          </div>

          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.gradientDirection")}</Label>
            <Select
              value={formData.overlay_gradient_direction || "to-b"}
              onValueChange={(value) => handleFieldChange("overlay_gradient_direction", value)}
            >
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="to-b">{t("admin.homepageTemplates.gradientDirection.toBottom")}</SelectItem>
                <SelectItem value="to-t">{t("admin.homepageTemplates.gradientDirection.toTop")}</SelectItem>
                <SelectItem value="to-r">{t("admin.homepageTemplates.gradientDirection.toRight")}</SelectItem>
                <SelectItem value="to-l">{t("admin.homepageTemplates.gradientDirection.toLeft")}</SelectItem>
                <SelectItem value="to-br">{t("admin.homepageTemplates.gradientDirection.toBottomRight")}</SelectItem>
                <SelectItem value="to-tr">{t("admin.homepageTemplates.gradientDirection.toTopRight")}</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="grid grid-cols-3 gap-4">
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.startOpacity")}</Label>
              <Input
                type="number"
                min="0"
                max="100"
                value={formData.overlay_gradient_from_opacity || 30}
                onChange={(e) => handleFieldChange("overlay_gradient_from_opacity", parseInt(e.target.value) || 0)}
              />
            </div>
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.middleOpacity")}</Label>
              <Input
                type="number"
                min="0"
                max="100"
                value={formData.overlay_gradient_via_opacity || 25}
                onChange={(e) => handleFieldChange("overlay_gradient_via_opacity", parseInt(e.target.value) || 0)}
              />
            </div>
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.endOpacity")}</Label>
              <Input
                type="number"
                min="0"
                max="100"
                value={formData.overlay_gradient_to_opacity || 40}
                onChange={(e) => handleFieldChange("overlay_gradient_to_opacity", parseInt(e.target.value) || 0)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.backgroundBlur")}: {formData.background_blur || 0}px</Label>
            <Slider
              value={[formData.background_blur || 0]}
              onValueChange={([value]) => handleFieldChange("background_blur", value)}
              max={50}
              step={1}
            />
          </div>
        </div>
      </TabsContent>

      {/* Content Tab */}
      <TabsContent value="content" className="space-y-4 mt-4">
        <div className="space-y-4">
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.titleChinese")}</Label>
            <Input value={formData.title_zh || ""} onChange={(e) => handleFieldChange("title_zh", e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.titleEnglish")}</Label>
            <Input value={formData.title_en || ""} onChange={(e) => handleFieldChange("title_en", e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.titlePortuguese")}</Label>
            <Input value={formData.title_pt || ""} onChange={(e) => handleFieldChange("title_pt", e.target.value)} />
          </div>

          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.descriptionChinese")}</Label>
            <Textarea value={formData.description_zh || ""} onChange={(e) => handleFieldChange("description_zh", e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.descriptionEnglish")}</Label>
            <Textarea value={formData.description_en || ""} onChange={(e) => handleFieldChange("description_en", e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>{t("admin.homepageTemplates.descriptionPortuguese")}</Label>
            <Textarea value={formData.description_pt || ""} onChange={(e) => handleFieldChange("description_pt", e.target.value)} />
          </div>
        </div>
      </TabsContent>

      {/* Buttons Tab */}
      <TabsContent value="buttons" className="space-y-4 mt-4">
        <Card>
          <CardHeader className="py-3">
            <CardTitle className="text-lg">{t("admin.homepageTemplates.primaryButton")}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.chinese")}</Label>
                <Input value={formData.primary_button_text_zh || ""} onChange={(e) => handleFieldChange("primary_button_text_zh", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.english")}</Label>
                <Input value={formData.primary_button_text_en || ""} onChange={(e) => handleFieldChange("primary_button_text_en", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.portuguese")}</Label>
                <Input value={formData.primary_button_text_pt || ""} onChange={(e) => handleFieldChange("primary_button_text_pt", e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.link")}</Label>
              <Input value={formData.primary_button_link || ""} onChange={(e) => handleFieldChange("primary_button_link", e.target.value)} />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="py-3">
            <CardTitle className="text-lg">{t("admin.homepageTemplates.secondaryButton")}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.chinese")}</Label>
                <Input value={formData.secondary_button_text_zh || ""} onChange={(e) => handleFieldChange("secondary_button_text_zh", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.english")}</Label>
                <Input value={formData.secondary_button_text_en || ""} onChange={(e) => handleFieldChange("secondary_button_text_en", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.portuguese")}</Label>
                <Input value={formData.secondary_button_text_pt || ""} onChange={(e) => handleFieldChange("secondary_button_text_pt", e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.link")}</Label>
              <Input value={formData.secondary_button_link || ""} onChange={(e) => handleFieldChange("secondary_button_link", e.target.value)} />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="py-3">
            <CardTitle className="text-lg">{t("admin.homepageTemplates.mapButton")}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.chinese")}</Label>
                <Input value={(formData as any).map_button_text_zh || ""} onChange={(e) => handleFieldChange("map_button_text_zh", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.english")}</Label>
                <Input value={(formData as any).map_button_text_en || ""} onChange={(e) => handleFieldChange("map_button_text_en", e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>{t("admin.homepageTemplates.portuguese")}</Label>
                <Input value={(formData as any).map_button_text_pt || ""} onChange={(e) => handleFieldChange("map_button_text_pt", e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <Label>{t("admin.homepageTemplates.link")}</Label>
              <Input value={(formData as any).map_button_link || ""} onChange={(e) => handleFieldChange("map_button_link", e.target.value)} placeholder="/map" />
            </div>
          </CardContent>
        </Card>

      </TabsContent>
    </Tabs>
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold">{t("admin.homepageTemplates")}</h1>
          <p className="text-muted-foreground mt-2">{t("admin.homepageTemplatesDescription")}</p>
        </div>
        <Button onClick={handleCreate}>
          <Plus className="w-4 h-4 mr-2" />
          {t("admin.homepageTemplates.createTemplate")}
        </Button>
      </div>

      {/* Template List */}
      <div className="grid gap-4">
        {templates?.map((template) => (
          <Card key={template.id} className={!template.is_active ? "opacity-60" : ""}>
            <CardContent className="p-4">
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2 text-muted-foreground">
                  <GripVertical className="w-5 h-5" />
                  <span className="text-sm font-medium">#{template.sort_order}</span>
                </div>
                
                {template.desktop_image_url && (
                  <img 
                    src={template.desktop_image_url} 
                    alt="Preview" 
                    className="w-24 h-16 object-cover rounded border"
                  />
                )}

                <div className="flex-1 min-w-0">
                  <h3 className="font-semibold truncate">{template.title_zh}</h3>
                  <p className="text-sm text-muted-foreground truncate">{template.description_zh}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <Clock className="w-3 h-3 text-muted-foreground" />
                      <span className="text-xs text-muted-foreground">{template.duration / 1000}{t("admin.homepageTemplates.seconds")}</span>
                      {(template as any).target_country && (
                        <span className="text-xs bg-primary/10 text-primary px-2 py-0.5 rounded-full">
                          🌍 {(template as any).target_country}
                        </span>
                      )}
                      {!(template as any).target_country && (
                        <span className="text-xs bg-muted text-muted-foreground px-2 py-0.5 rounded-full">
                          🌐 默认
                        </span>
                      )}
                    </div>
                </div>

                <div className="flex items-center gap-2">
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setPreviewTemplate(template)}
                    title={t("admin.homepageTemplates.preview") || "预览"}
                  >
                    <Play className="w-4 h-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => handleToggleActive(template)}
                    title={template.is_active ? t("admin.homepageTemplates.hide") : t("admin.homepageTemplates.show")}
                  >
                    {template.is_active ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
                  </Button>
                  <Button variant="ghost" size="icon" onClick={() => handleEdit(template)}>
                    <Edit className="w-4 h-4" />
                  </Button>
                  <AlertDialog>
                    <AlertDialogTrigger asChild>
                      <Button variant="ghost" size="icon" className="text-destructive hover:text-destructive">
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent>
                      <AlertDialogHeader>
                        <AlertDialogTitle>{t("admin.confirmDelete")}</AlertDialogTitle>
                        <AlertDialogDescription>
                          {t("admin.homepageTemplates.deleteTemplateConfirm")}
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
                        <AlertDialogAction onClick={() => handleDelete(template.id)}>{t("common.delete")}</AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}

        {(!templates || templates.length === 0) && (
          <Card>
            <CardContent className="p-8 text-center text-muted-foreground">
              {t("admin.homepageTemplates.noTemplates")}
            </CardContent>
          </Card>
        )}
      </div>

      {/* Edit/Create Dialog */}
      <Dialog open={!!editingTemplate || isCreateDialogOpen} onOpenChange={closeDialog}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingTemplate ? t("admin.homepageTemplates.editTemplate") : t("admin.homepageTemplates.createTemplate")}</DialogTitle>
            <DialogDescription>
              {t("admin.homepageTemplates.configureTemplate")}
            </DialogDescription>
          </DialogHeader>

          {renderTemplateForm()}

          <div className="flex justify-between gap-2 mt-4">
            <Button 
              variant="outline" 
              onClick={() => setPreviewTemplate(formData)}
              disabled={!formData.desktop_image_url && !formData.mobile_image_url}
            >
              <Play className="w-4 h-4 mr-2" />
              预览
            </Button>
            <div className="flex gap-2">
              <Button variant="outline" onClick={closeDialog}>{t("common.cancel")}</Button>
              <Button onClick={handleSave} disabled={createTemplate.isPending || updateTemplate.isPending}>
                {(createTemplate.isPending || updateTemplate.isPending) && (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                )}
                <Save className="w-4 h-4 mr-2" />
                {t("common.save")}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Preview Dialog */}
      {previewTemplate && (
        <div className="fixed inset-0 z-50 bg-black">
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-4 right-4 z-50 text-white hover:bg-white/20"
            onClick={() => setPreviewTemplate(null)}
          >
            <X className="w-6 h-6" />
          </Button>
          <TemplatePreview template={previewTemplate} onClose={() => setPreviewTemplate(null)} />
        </div>
      )}

      {/* Crop Dialog */}
      {cropImageSource && (
        <HomepageMediaCropDialog
          open={cropDialogOpen}
          onOpenChange={(open) => {
            setCropDialogOpen(open);
            if (!open) setCropImageSource(null);
          }}
          imageSource={cropImageSource}
          deviceType={cropDeviceType}
          onCropComplete={handleCropComplete}
        />
      )}
    </div>
  );
};

export default AdminHomepageTemplates;
