import { useState, useRef, useCallback, useEffect } from "react";
import { useTranslation } from "react-i18next";
import ReactCrop, { Crop, PixelCrop, centerCrop, makeAspectCrop } from "react-image-crop";
import "react-image-crop/dist/ReactCrop.css";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Crop as CropIcon, Maximize2, Monitor, Tablet, Smartphone, Loader2 } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";

type DeviceType = "desktop" | "tablet" | "mobile";

interface HomepageMediaCropDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  imageSource: File | string; // Can be File or URL string
  deviceType: DeviceType;
  onCropComplete: (croppedFile: File, deviceType: DeviceType) => void;
}

// Aspect ratios for different devices
const DEVICE_CONFIGS: Record<DeviceType, { width: number; height: number; aspect: number; label: string; icon: any }> = {
  desktop: { width: 1920, height: 1080, aspect: 16 / 9, label: "桌面端 16:9", icon: Monitor },
  tablet: { width: 1024, height: 768, aspect: 4 / 3, label: "平板端 4:3", icon: Tablet },
  mobile: { width: 750, height: 1334, aspect: 9 / 16, label: "移动端 9:16", icon: Smartphone },
};

function centerAspectCrop(
  mediaWidth: number,
  mediaHeight: number,
  aspect: number,
) {
  return centerCrop(
    makeAspectCrop(
      {
        unit: '%',
        width: 90,
      },
      aspect,
      mediaWidth,
      mediaHeight,
    ),
    mediaWidth,
    mediaHeight,
  );
}

export function HomepageMediaCropDialog({
  open,
  onOpenChange,
  imageSource,
  deviceType,
  onCropComplete,
}: HomepageMediaCropDialogProps) {
  const { t } = useTranslation();
  const [imgSrc, setImgSrc] = useState("");
  const [crop, setCrop] = useState<Crop>();
  const [completedCrop, setCompletedCrop] = useState<PixelCrop>();
  const [selectedDevice, setSelectedDevice] = useState<DeviceType>(deviceType);
  const imgRef = useRef<HTMLImageElement>(null);
  const [isCropping, setIsCropping] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const config = DEVICE_CONFIGS[selectedDevice];
  const DeviceIcon = config.icon;

  useEffect(() => {
    if (open && imageSource) {
      setSelectedDevice(deviceType);
      setCrop(undefined);
      setCompletedCrop(undefined);
      
      if (typeof imageSource === 'string') {
        // It's a URL - load it directly
        setIsLoading(true);
        setImgSrc(imageSource);
      } else {
        // It's a File - read it
        setIsLoading(true);
        const reader = new FileReader();
        reader.addEventListener("load", () => {
          setImgSrc(reader.result?.toString() || "");
        });
        reader.readAsDataURL(imageSource);
      }
    }
  }, [open, imageSource, deviceType]);

  const onImageLoad = useCallback((e: React.SyntheticEvent<HTMLImageElement>) => {
    setIsLoading(false);
    const { width, height } = e.currentTarget;
    setCrop(centerAspectCrop(width, height, config.aspect));
  }, [config.aspect]);

  // Update crop when device type changes
  useEffect(() => {
    if (imgRef.current && imgRef.current.complete) {
      const { width, height } = imgRef.current;
      if (width && height) {
        setCrop(centerAspectCrop(width, height, config.aspect));
      }
    }
  }, [selectedDevice, config.aspect]);

  const getCroppedImg = useCallback(
    async (image: HTMLImageElement, crop: PixelCrop): Promise<Blob> => {
      const canvas = document.createElement("canvas");
      const ctx = canvas.getContext("2d");

      if (!ctx) {
        throw new Error("No 2d context");
      }

      const scaleX = image.naturalWidth / image.width;
      const scaleY = image.naturalHeight / image.height;

      // Calculate output dimensions while maintaining aspect ratio
      const cropWidthPx = crop.width * scaleX;
      const cropHeightPx = crop.height * scaleY;
      
      // Scale down to recommended size if larger
      let outputWidth = cropWidthPx;
      let outputHeight = cropHeightPx;
      
      if (outputWidth > config.width || outputHeight > config.height) {
        const scale = Math.min(config.width / outputWidth, config.height / outputHeight);
        outputWidth = outputWidth * scale;
        outputHeight = outputHeight * scale;
      }
      
      canvas.width = outputWidth;
      canvas.height = outputHeight;

      ctx.imageSmoothingQuality = "high";

      ctx.drawImage(
        image,
        crop.x * scaleX,
        crop.y * scaleY,
        cropWidthPx,
        cropHeightPx,
        0,
        0,
        canvas.width,
        canvas.height
      );

      return new Promise((resolve, reject) => {
        canvas.toBlob(
          (blob) => {
            if (!blob) {
              reject(new Error("Canvas is empty"));
              return;
            }
            resolve(blob);
          },
          "image/jpeg",
          0.92
        );
      });
    },
    [config]
  );

  const handleCropConfirm = useCallback(async () => {
    if (!completedCrop || !imgRef.current) return;

    setIsCropping(true);
    try {
      const croppedBlob = await getCroppedImg(imgRef.current, completedCrop);
      const fileName = typeof imageSource === 'string' 
        ? `cropped-${selectedDevice}-${Date.now()}.jpg`
        : imageSource.name;
      const croppedFile = new File([croppedBlob], fileName, {
        type: "image/jpeg",
      });

      onCropComplete(croppedFile, selectedDevice);
      onOpenChange(false);
    } catch (error) {
      console.error("Error cropping image:", error);
    } finally {
      setIsCropping(false);
    }
  }, [completedCrop, imageSource, selectedDevice, onCropComplete, onOpenChange, getCroppedImg]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-[95vw] sm:max-w-4xl max-h-[95vh] overflow-hidden flex flex-col p-0">
        <DialogHeader className="px-4 sm:px-6 pt-4 sm:pt-6 pb-4 border-b">
          <DialogTitle className="text-lg sm:text-xl flex items-center gap-2">
            <CropIcon className="w-5 h-5 text-primary" />
            裁剪图片
          </DialogTitle>
          <DialogDescription className="text-xs sm:text-sm">
            拖动选择要保留的区域，裁剪后将用于主页轮播
          </DialogDescription>
        </DialogHeader>

        <div className="px-4 sm:px-6 py-4 space-y-4 overflow-y-auto">
          {/* Device Type Selector */}
          <Tabs value={selectedDevice} onValueChange={(v) => setSelectedDevice(v as DeviceType)}>
            <TabsList className="grid w-full grid-cols-3">
              <TabsTrigger value="desktop" className="flex items-center gap-1">
                <Monitor className="w-4 h-4" />
                <span className="hidden sm:inline">桌面端</span>
              </TabsTrigger>
              <TabsTrigger value="tablet" className="flex items-center gap-1">
                <Tablet className="w-4 h-4" />
                <span className="hidden sm:inline">平板端</span>
              </TabsTrigger>
              <TabsTrigger value="mobile" className="flex items-center gap-1">
                <Smartphone className="w-4 h-4" />
                <span className="hidden sm:inline">移动端</span>
              </TabsTrigger>
            </TabsList>
          </Tabs>

          <Alert className="border-primary/20 bg-primary/5">
            <DeviceIcon className="h-4 w-4" />
            <AlertDescription className="text-xs sm:text-sm">
              <div className="flex flex-col sm:flex-row sm:items-center gap-2">
                <span className="font-medium">推荐尺寸:</span>
                <Badge variant="secondary" className="w-fit">
                  <Maximize2 className="w-3 h-3 mr-1" />
                  {config.width} × {config.height} px ({config.label})
                </Badge>
              </div>
            </AlertDescription>
          </Alert>

          <div className="relative w-full overflow-hidden rounded-lg border bg-muted/30 min-h-[200px]">
            {isLoading && (
              <div className="absolute inset-0 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
              </div>
            )}
            {imgSrc && (
              <ReactCrop
                crop={crop}
                onChange={(c) => setCrop(c)}
                onComplete={(c) => setCompletedCrop(c)}
                aspect={config.aspect}
                className="max-h-[50vh] sm:max-h-[55vh] flex items-center justify-center"
              >
                <img
                  ref={imgRef}
                  src={imgSrc}
                  alt="Crop preview"
                  onLoad={onImageLoad}
                  crossOrigin="anonymous"
                  className="max-w-full max-h-[50vh] sm:max-h-[55vh] h-auto object-contain"
                />
              </ReactCrop>
            )}
          </div>
        </div>

        <DialogFooter className="px-4 sm:px-6 pb-4 sm:pb-6 pt-4 border-t gap-2 sm:gap-0">
          <Button
            type="button"
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isCropping}
            className="w-full sm:w-auto"
          >
            {t("common.cancel")}
          </Button>
          <Button
            type="button"
            onClick={handleCropConfirm}
            disabled={!completedCrop || isCropping || isLoading}
            className="w-full sm:w-auto"
          >
            {isCropping ? "处理中..." : "确认裁剪"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
